  topicHeaders.forEach(h => maxScoreRow[h] = "10"); // Default placeholder max score
  maxScoreRow["Total"] = "";
  maxScoreRow["Percentage (%)"] = "";

  // Create rows for 50 students
  const rows = [maxScoreRow];
  for (let i = 1; i <= 50; i++) {
    const row: any = {
      "S/N": i,
      "Student Name": ""
    };
    topicHeaders.forEach(header => {
      row[header] = ""; 
    });
    row["Total"] = "";
    row["Percentage (%)"] = "";
    rows.push(row);
  }

  const worksheet = XLSX.utils.json_to_sheet(rows, { header: finalHeaders });

  // Set column widths
  const wscols = [
    { wch: 5 },  
    { wch: 30 }, 
    ...topicHeaders.map(() => ({ wch: 18 })), 
    { wch: 10 },  
    { wch: 15 },  
  ];
  worksheet['!cols'] = wscols;

  const workbook = XLSX.utils.book_new();
  XLSX.utils.book_append_sheet(workbook, worksheet, "Marks Record Book");

