  const doc = generateSchemePdfDoc(scheme);
  doc.save(`${scheme.metadata.subject}_Scheme.pdf`);
};

export const exportToExcel = (scheme: SchemeBook) => {
  const workbook = generateExcelWorkbook(scheme);
  XLSX.writeFile(workbook, `${scheme.metadata.subject}_Scheme.xlsx`);
};

import { GoogleGenAI, Type } from "@google/genai";
import { SchemeMetadata, Lesson } from "../types";

export interface ExtractedSyllabusInfo {
  subject: string;
  form: string;
  recommendedWeeks: number;
}

// Peak into the syllabus to pre-fill the form
export const extractSyllabusInfo = async (
  syllabusFile: { data: string, mimeType: string }
): Promise<ExtractedSyllabusInfo> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: {
      parts: [
        { text: "Analyze this syllabus document carefully. Identify the exact subject title (e.g., 'Chemistry', 'English Language'), the target grade or 'form' level, and suggest a logical duration in weeks (typically 10-14) needed to cover the topics provided." },
        { inlineData: syllabusFile }
      ]
    },
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          subject: { type: Type.STRING },
          form: { type: Type.STRING },
          recommendedWeeks: { type: Type.INTEGER },
        },
        required: ["subject", "form", "recommendedWeeks"],
      }
    }
  });

  try {
    return JSON.parse(response.text.trim());
  } catch (error) {
    console.error("Extraction failed", error);
    return { subject: "", form: "", recommendedWeeks: 12 };
  }
};

// Step 1: Generate the Scheme Book Table
export const generateSchemeBook = async (
  metadata: SchemeMetadata, 
  syllabusFile?: { data: string, mimeType: string }
): Promise<Partial<Lesson>[]> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const totalLessons = metadata.weeks * metadata.lessonsPerWeek;

  const textPrompt = `
    Act as a Senior Curriculum Specialist and Instructional Designer. 
    Create a professional, high-quality Scheme of Work for:
    Subject: ${metadata.subject} 
    Level: Form/Grade ${metadata.form} 
    Term: ${metadata.term}
    Total Capacity: ${totalLessons} lessons over ${metadata.weeks} weeks.

    ${syllabusFile ? 'CRITICAL: Align the content strictly with the topics, sub-topics, and learning outcomes identified in the attached syllabus document. Do not use generic placeholders; use the specific language from the file.' : 'Use standard international curriculum standards for this subject and grade level.'}

    DESIGN PRINCIPLES:
    1. PROGRESSION: Ensure a logical scaffolding of concepts (from foundational to complex).
    2. SMART OBJECTIVES: Learning objectives must be Specific, Measurable, Achievable, Relevant, and Time-bound.
    3. ENGAGEMENT: Activities should be student-centered and diverse (collaborative, inquiry-based, practical).
    4. ASSESSMENT: Include formative assessment methods for every lesson.

    OUTPUT: Provide exactly ${totalLessons} lessons in a structured JSON array.
  `;

  const contents = syllabusFile 
    ? { parts: [{ text: textPrompt }, { inlineData: syllabusFile }] }
    : textPrompt;

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: contents,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            week: { type: Type.INTEGER },
            lessonNumber: { type: Type.INTEGER },
            topic: { type: Type.STRING },
            objectives: { type: Type.STRING, description: "Action-oriented objectives (e.g., 'Students will be able to...')" },
            concepts: { type: Type.STRING, description: "Key vocabulary and theoretical pillars" },
            activities: { type: Type.STRING, description: "Detailed student-teacher interaction flow" },
            resources: { type: Type.STRING, description: "Specific teaching aids and tech tools" },
            assessment: { type: Type.STRING, description: "Formative/Summative check-ins" },
            homework: { type: Type.STRING, description: "Extension or reinforcement task" },
            evaluation: { type: Type.STRING, description: "Detailed criteria for lesson success" },
          },
          required: ["week", "lessonNumber", "topic", "objectives", "concepts", "activities", "resources", "assessment", "homework", "evaluation"],
        }
      }
    }
  });

  try {
    return JSON.parse(response.text.trim());
  } catch (error) {
    throw new Error("Failed to parse scheme book. Please try again.");
  }
};

// Step 2: Generate resources for a specific lesson
export const generateLessonResourcesContent = async (
  lesson: Lesson,
  metadata: SchemeMetadata
): Promise<Pick<Lesson, 'lessonPlanContent' | 'worksheetContent' | 'slidesContent' | 'videoGuideDescription'>> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: `
      Act as an expert Teacher Trainer. Generate comprehensive, high-engagement teaching resources for:

      CONTEXT:
      - Subject: ${metadata.subject} (Form ${metadata.form})
      - Lesson Topic: ${lesson.topic}
      - Key Objectives: ${lesson.objectives}
      - Key Concepts: ${lesson.concepts}

      PEDAGOGICAL REQUIREMENTS:

      1. 'lessonPlanContent' (Markdown): 
         - Use a standard format: 
           - Anticipatory Set/Hook (5 mins): Engage prior knowledge.
           - Direct Instruction (10-15 mins): Core explanation with teacher scripts.
           - Guided Practice (15 mins): Collaborative task with scaffolding.
           - Independent Practice (10 mins): Student check.
           - Closure/Plenary (5 mins): Recap and 'exit ticket'.
           - Misconceptions: List 2 common pitfalls and how to address them.
           - Differentiation: One strategy for 'Support' and one for 'Challenge'.

      2. 'worksheetContent' (Markdown): 
         - Title the worksheet clearly.
         - Include 5-6 questions of increasing difficulty (Bloom's Taxonomy):
           - 2 Recall/Understanding questions.
           - 2 Application/Analysis questions.
           - 1 Evaluation/Creation 'Challenge' question.
         - Provide clear blank spaces for student answers.

      3. 'slidesContent' (Array of 6 strings):
         - Slide 1: Title & Hook.
         - Slide 2: Learning Objectives (in student-friendly 'I can' language).
         - Slide 3: Key Concepts/Vocabulary definitions.
         - Slide 4: Main Instructional Diagram or Process explanation.
         - Slide 5: Guided Activity instructions.
         - Slide 6: Summary & Homework.

      4. 'videoGuideDescription' (Text):
         - A structured narrative outline for a teacher recording a 3-minute explanation video. 
         - Include what to say and what to point at on a screen.
    `,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          lessonPlanContent: { type: Type.STRING },
          worksheetContent: { type: Type.STRING },
          slidesContent: { type: Type.ARRAY, items: { type: Type.STRING } },
          videoGuideDescription: { type: Type.STRING },
        },
        required: ["lessonPlanContent", "worksheetContent", "slidesContent", "videoGuideDescription"],
      }
    }
  });

  return JSON.parse(response.text.trim());
};

import React, { useState, useRef } from 'react';
import { SchemeMetadata } from '../types';
import { getAcademicYears } from '../utils/dateUtils';
import { SUBJECT_TEMPLATES } from '../constants';
import { FileText, Sparkles, Upload, FileUp, X, Loader2, CheckCircle2, Calendar, Database } from 'lucide-react';
import { extractSyllabusInfo } from '../services/geminiService';

interface InputFormProps {
  onGenerate: (metadata: SchemeMetadata, syllabusFile?: { data: string, mimeType: string }) => void;
}

const InputForm: React.FC<InputFormProps> = ({ onGenerate }) => {
  const [formData, setFormData] = useState<SchemeMetadata>({
    subject: '',
    form: '',
    term: '1',
    weeks: 12,
    lessonsPerWeek: 5,
    teacherName: '',
    school: '',
    academicYear: getAcademicYears()[0],
    startDate: new Date().toISOString().split('T')[0]
  });

  const [selectedFile, setSelectedFile] = useState<File | null>(null);
  const [fileBase64, setFileBase64] = useState<string | null>(null);
  const [isExtracting, setIsExtracting] = useState(false);
  const [isExtracted, setIsExtracted] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: name === 'weeks' || name === 'lessonsPerWeek' ? parseInt(value) || 0 : value
    }));
  };

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file && file.type === 'application/pdf') {
      setSelectedFile(file);
      const reader = new FileReader();
      reader.onload = async (event) => {
        const base64 = (event.target?.result as string).split(',')[1];
        setFileBase64(base64);

        setIsExtracting(true);
        setIsExtracted(false);
        try {
          const info = await extractSyllabusInfo({ data: base64, mimeType: 'application/pdf' });
          setFormData(prev => ({
            ...prev,
            subject: info.subject || prev.subject,
            form: info.form || prev.form,
            weeks: info.recommendedWeeks || prev.weeks
          }));
          setIsExtracted(true);
        } catch (err) {
          console.error("Auto-extraction failed", err);
        } finally {
          setIsExtracting(false);
        }
      };
      reader.readAsDataURL(file);
    } else if (file) {
      alert("Please upload a PDF file.");
      e.target.value = '';
    }
  };

  const removeFile = () => {
    setSelectedFile(null);
    setFileBase64(null);
    setIsExtracted(false);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const handleTemplateLoad = (templateId: string) => {
    const template = SUBJECT_TEMPLATES.find(t => t.id === templateId);
    if (template) {
      setFormData(prev => ({
        ...prev,
        subject: template.subject,
        form: template.form
      }));
      setIsExtracted(false);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.subject) {
      alert("Please specify a subject.");
      return;
    }
    onGenerate(
      formData, 
      fileBase64 ? { data: fileBase64, mimeType: 'application/pdf' } : undefined
    );
  };

  return (
    <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
      <div className="bg-slate-50 border-b border-slate-200 px-6 py-4 flex items-center justify-between">
        <h2 className="text-lg font-semibold flex items-center gap-2 text-slate-800">
          <FileText className="w-5 h-5 text-indigo-600" />
          Setup Scheme Book
        </h2>
        <div className="flex gap-2">
          <select 
            onChange={(e) => handleTemplateLoad(e.target.value)}
            className="text-sm border-slate-300 rounded-lg py-1 px-3 bg-white focus:ring-indigo-500 focus:border-indigo-500"
          >
            <option value="">Quick Templates</option>
            {SUBJECT_TEMPLATES.map(t => (
              <option key={t.id} value={t.id}>{t.name}</option>
            ))}
          </select>
        </div>
      </div>

      <form onSubmit={handleSubmit} className="p-6 space-y-6">
        <div className="space-y-2">
          <label className="text-sm font-medium text-slate-700 flex items-center gap-2">
            <Upload className="w-4 h-4 text-slate-400" />
            Upload Syllabus PDF
          </label>
          <div 
            onClick={() => !selectedFile && !isExtracting && fileInputRef.current?.click()}
            className={`relative border-2 border-dashed rounded-xl p-6 transition-all duration-200 cursor-pointer ${
              selectedFile ? 'border-indigo-200 bg-indigo-50' : 'border-slate-200 hover:border-indigo-400 hover:bg-slate-50'
            } ${isExtracting ? 'opacity-70 cursor-wait' : ''}`}
          >
            <input 
              type="file" 
              ref={fileInputRef} 
              className="hidden" 
              accept="application/pdf"
              onChange={handleFileChange}
              disabled={isExtracting}
            />
            {selectedFile ? (
              <div className="flex items-center justify-between">
                <div className="flex items-center gap-3">
                  <div className={`p-2 rounded-lg ${isExtracting ? 'bg-indigo-100 animate-pulse' : 'bg-emerald-100'}`}>
                    {isExtracting ? <Loader2 className="w-5 h-5 text-indigo-600 animate-spin" /> : <FileUp className="w-5 h-5 text-emerald-600" />}
                  </div>
                  <div>
                    <div className="flex items-center gap-2">
                       <p className="text-sm font-semibold text-slate-800 truncate max-w-[200px] md:max-w-md">{selectedFile.name}</p>
                       {isExtracted && <CheckCircle2 className="w-4 h-4 text-emerald-500" />}
                    </div>
                    <p className="text-xs text-slate-500">
                      {isExtracting ? 'AI is analyzing syllabus...' : isExtracted ? 'Subject & Grade auto-filled!' : 'Syllabus Attached'}
                    </p>
                  </div>
                </div>
                {!isExtracting && (
                  <button 
                    type="button"
                    onClick={(e) => { e.stopPropagation(); removeFile(); }}
                    className="p-1.5 hover:bg-indigo-200 rounded-full text-indigo-600 transition-colors"
                  >
                    <X className="w-4 h-4" />
                  </button>
                )}
              </div>
            ) : (
              <div className="text-center">
                <div className="mx-auto w-10 h-10 bg-slate-100 rounded-full flex items-center justify-center mb-2">
                  <Upload className="w-5 h-5 text-slate-400" />
                </div>
                <p className="text-sm font-medium text-slate-600">Click to upload your syllabus PDF</p>
                <p className="text-xs text-slate-400 mt-1">AI will derive content directly from the file</p>
              </div>
            )}
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
          <div className="space-y-2">
            <label className="text-sm font-medium text-slate-700 flex items-center gap-1.5">
              Subject
              {isExtracted && <span className="flex items-center gap-1 text-[10px] bg-emerald-100 text-emerald-700 px-1.5 py-0.5 rounded-full font-bold uppercase"><Database className="w-2.5 h-2.5" /> Syllabus Derived</span>}
            </label>
            <input
              required
              name="subject"
              value={formData.subject}
              onChange={handleChange}
              className={`w-full border-slate-300 rounded-lg px-3 py-2 focus:ring-indigo-500 focus:border-indigo-500 border transition-all ${isExtracted ? 'bg-emerald-50 border-emerald-200 ring-1 ring-emerald-100' : ''}`}
              placeholder="e.g. Mathematics"
            />
          </div>
          <div className="space-y-2">
            <label className="text-sm font-medium text-slate-700">Form / Class</label>
            <input
              required
              name="form"
              value={formData.form}
              onChange={handleChange}
              className={`w-full border-slate-300 rounded-lg px-3 py-2 focus:ring-indigo-500 focus:border-indigo-500 border transition-all ${isExtracted ? 'bg-emerald-50 border-emerald-200' : ''}`}
              placeholder="e.g. Form 4"
            />
          </div>
          <div className="space-y-2">
            <label className="text-sm font-medium text-slate-700">Term</label>
            <select
              name="term"
              value={formData.term}
              onChange={handleChange}
              className="w-full border-slate-300 rounded-lg px-3 py-2 focus:ring-indigo-500 focus:border-indigo-500 border bg-white"
            >
              <option value="1">1st Term</option>
              <option value="2">2nd Term</option>
              <option value="3">3rd Term</option>
            </select>
          </div>
          <div className="space-y-2">
            <label className="text-sm font-medium text-slate-700 flex items-center gap-1.5">
              <Calendar className="w-3.5 h-3.5 text-indigo-500" />
              Term Start Date
            </label>
            <input
              required
              type="date"
              name="startDate"
              value={formData.startDate}
              onChange={handleChange}
              className="w-full border-slate-300 rounded-lg px-3 py-2 focus:ring-indigo-500 focus:border-indigo-500 border"
            />
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
          <div className="space-y-2">
            <label className="text-sm font-medium text-slate-700">Total Weeks</label>
            <input
              required
              type="number"
              min="1"
              max="20"
              name="weeks"
              value={formData.weeks}
              onChange={handleChange}
              className={`w-full border-slate-300 rounded-lg px-3 py-2 focus:ring-indigo-500 focus:border-indigo-500 border ${isExtracted ? 'bg-emerald-50 border-emerald-200' : ''}`}
            />
          </div>
          <div className="space-y-2">
            <label className="text-sm font-medium text-slate-700">Lessons per Week</label>
            <input
              required
              type="number"
              min="1"
              max="10"
              name="lessonsPerWeek"
