import React, { useState, useEffect } from 'react';
import { Download, FileSpreadsheet, Layout, RotateCcw, Printer, PlusCircle, Sparkles, FolderArchive, Package, Info, GraduationCap, FileText } from 'lucide-react';
import InputForm from './components/InputForm';
import SchemeTable from './components/SchemeTable';
import LoadingOverlay from './components/LoadingOverlay';
import { SchemeBook, SchemeMetadata, Lesson } from './types';
import { generateSchemeBook, generateLessonResourcesContent } from './services/geminiService';
import { getWeekEndingDate } from './utils/dateUtils';
import { exportToPDF, exportToExcel, exportToWord, downloadFullPackageZip, exportRecordBookExcel } from './utils/exportUtils';

const STORAGE_KEY = 'schemegenie_v3';

const App: React.FC = () => {
  const [activeScheme, setActiveScheme] = useState<SchemeBook | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [isExportingFull, setIsExportingFull] = useState(false);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        if (Array.isArray(parsed) && parsed.length > 0) {
          setActiveScheme(parsed[0]);
        }
      } catch (e) {
        console.error("Failed to load saved drafts", e);
      }
    }
  }, []);

  useEffect(() => {
    if (activeScheme) {
      localStorage.setItem(STORAGE_KEY, JSON.stringify([activeScheme]));
    }
  }, [activeScheme]);

  const handleGenerate = async (metadata: SchemeMetadata, syllabusFile?: { data: string, mimeType: string }) => {
    setIsLoading(true);
    setError(null);
    try {
      const lessonData = await generateSchemeBook(metadata, syllabusFile);

      const completeLessons: Lesson[] = lessonData.map((l, index) => {
        const week = l.week || Math.floor(index / metadata.lessonsPerWeek) + 1;
        return {
          id: `lesson-${Date.now()}-${index}`,
          week: week,
          lessonNumber: l.lessonNumber || (index % metadata.lessonsPerWeek) + 1,
          topic: l.topic || '',
          objectives: l.objectives || '',
          concepts: l.concepts || '',
          activities: l.activities || '',
          resources: l.resources || '',
          assessment: l.assessment || '',
          homework: l.homework || '',
          evaluation: l.evaluation || '',
          remarks: '', // Blank column for handwritten notes/evaluation
          weekEnding: getWeekEndingDate(metadata.startDate, week),
        };
      });

      const newScheme: SchemeBook = {
        id: `scheme-${Date.now()}`,
        metadata,
        lessons: completeLessons,
        createdAt: Date.now()
      };

      setActiveScheme(newScheme);
    } catch (err: any) {
      setError("AI is currently busy or the syllabus is too large. Please try again with fewer weeks or a simpler subject.");
    } finally {
      setIsLoading(false);
    }
  };

  const handleGenerateResources = async (lesson: Lesson) => {
    if (!activeScheme) return;

    // Set loading state for this lesson
    updateLesson(lesson.id, 'isGeneratingResources', true);

    try {
      const resources = await generateLessonResourcesContent(lesson, activeScheme.metadata);

      setActiveScheme(prev => {
        if (!prev) return null;
        return {
          ...prev,
          lessons: prev.lessons.map(l => l.id === lesson.id ? { 
            ...l, 
            ...resources, 
            isGeneratingResources: false 
          } : l)
        };
      });
    } catch (err) {
      alert("Failed to build bundle for this lesson. Please try again.");
      updateLesson(lesson.id, 'isGeneratingResources', false);
    }
  };

  const handleFullPackageDownload = async () => {
    if (!activeScheme) return;

    const missingResources = activeScheme.lessons.filter(l => !l.lessonPlanContent);
    if (missingResources.length > 0) {
      if (!confirm(`You have ${missingResources.length} lessons without generated bundles. They will only contain basic placeholders in the full package. Proceed?`)) {
        return;
      }
    }

    setIsExportingFull(true);
    try {
      await downloadFullPackageZip(activeScheme);
    } catch (e) {
      alert("Error packaging resources. Try again.");
    } finally {
      setIsExportingFull(false);
    }
  };

  const updateLesson = (id: string, field: keyof Lesson, value: any) => {
    setActiveScheme(prev => {
      if (!prev) return null;
      return {
        ...prev,
        lessons: prev.lessons.map(l => l.id === id ? { ...l, [field]: value } : l)
      };
    });
  };

  const handleReset = () => {
    if (confirm("Reset everything? Draft will be lost.")) {
      setActiveScheme(null);
      localStorage.removeItem(STORAGE_KEY);
    }
  };

  const handleDownloadRecordBook = () => {
    if (!activeScheme) return;
    exportRecordBookExcel(activeScheme);
  };

  return (
    <div className="min-h-screen pb-20">
      <header className="bg-slate-800 text-white shadow-lg no-print">
        <div className="container mx-auto px-6 py-4 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="bg-indigo-600 p-2 rounded-lg">
              <Package className="w-6 h-6 text-white" />
            </div>
            <div>
              <h1 className="text-xl font-bold tracking-tight">SchemeGenie</h1>
              <p className="text-xs text-indigo-300 font-medium italic">Advanced Curriculum Hub</p>
            </div>
          </div>

          <div className="flex items-center gap-4">
            {activeScheme && (
              <div className="hidden md:flex items-center gap-2">
                <button 
                  onClick={handleDownloadRecordBook}
                  className="flex items-center gap-2 bg-emerald-600 hover:bg-emerald-500 text-white px-4 py-2 rounded-lg text-sm font-bold shadow-md transition-all"
                >
                  <GraduationCap className="w-4 h-4" />
                  Record Book
                </button>
                <button 
                  onClick={handleFullPackageDownload} 
                  disabled={isExportingFull}
                  className="flex items-center gap-2 bg-indigo-600 hover:bg-indigo-500 text-white px-4 py-2 rounded-lg text-sm font-bold shadow-md disabled:opacity-50 transition-all"
                >
                  <FolderArchive className="w-4 h-4" />
                  Package Export
                </button>
                <div className="h-6 w-px bg-slate-700 mx-1"></div>
                <button onClick={() => exportToPDF(activeScheme)} className="flex items-center gap-2 bg-slate-700 hover:bg-slate-600 text-white px-4 py-2 rounded-lg text-sm font-medium transition-colors">
                  <Download className="w-4 h-4" /> PDF
                </button>
                <button onClick={() => exportToWord(activeScheme)} className="flex items-center gap-2 bg-slate-700 hover:bg-slate-600 text-white px-4 py-2 rounded-lg text-sm font-medium transition-colors">
                  <FileText className="w-4 h-4" /> Word
                </button>
              </div>
            )}
            <button onClick={handleReset} className="p-2 hover:bg-slate-700 rounded-lg text-slate-400 hover:text-white transition-colors">
              <RotateCcw className="w-5 h-5" />
            </button>
          </div>
        </div>
      </header>

      <main className="container mx-auto px-6 py-8">
        {!activeScheme ? (
          <div className="max-w-4xl mx-auto space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-700">
            <div className="text-center space-y-4 py-10">
              <h2 className="text-5xl font-extrabold text-slate-800 tracking-tight">Term Planning Redefined</h2>
              <p className="text-lg text-slate-500 max-w-2xl mx-auto leading-relaxed">
                Step 1: Generate your <span className="text-indigo-600 font-bold">Scheme Book</span>. <br/>
                Step 2: Build individual <span className="text-indigo-600 font-bold">Resource Bundles</span> for each lesson.
              </p>
            </div>

            <InputForm onGenerate={handleGenerate} />

            {error && (
              <div className="bg-red-50 border border-red-200 text-red-700 px-6 py-4 rounded-xl flex items-center gap-3">
                <Layout className="w-5 h-5 text-red-600" />
                {error}
              </div>
            )}
          </div>
        ) : (
          <div className="space-y-6 animate-in fade-in duration-500">
            <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6 flex flex-wrap items-center justify-between gap-6 no-print">
              <div className="flex gap-8">
                <div>
                  <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest block mb-1">Scheme Detail</label>
                  <p className="text-lg font-bold text-slate-800">{activeScheme.metadata.subject} | {activeScheme.metadata.form}</p>
                </div>
                <div>
                  <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest block mb-1">Status</label>
                  <p className="text-sm font-bold text-emerald-600 flex items-center gap-1">
                    <Sparkles className="w-3 h-3" /> Scheme Ready
                  </p>
                </div>
              </div>
              <div className="flex gap-3">
                <button onClick={() => setActiveScheme(null)} className="bg-white border border-slate-200 text-slate-700 hover:bg-slate-50 px-4 py-2 rounded-lg text-sm font-semibold transition-all flex items-center gap-2">
                  <PlusCircle className="w-4 h-4" /> Reset
                </button>
                <button onClick={() => window.print()} className="bg-slate-100 text-slate-700 hover:bg-slate-200 px-4 py-2 rounded-lg text-sm font-semibold transition-all flex items-center gap-2">
                  <Printer className="w-4 h-4" /> Print
                </button>
              </div>
            </div>

            <div className="bg-indigo-50 border border-indigo-100 p-4 rounded-xl flex items-start gap-4 no-print">
              <div className="bg-indigo-600 p-2 rounded-lg text-white">
                <Info className="w-5 h-5" />
              </div>
              <div>
                <h4 className="font-bold text-indigo-900 text-sm">Step 2: Build Your Bundles</h4>
                <p className="text-indigo-700 text-xs mt-1">
                  Click <span className="font-bold">"Build Bundle"</span> in the table below to generate detailed Lesson Plans, Worksheets, and Slides for any specific lesson.
                  You can also download a <span className="font-bold">Record Book</span> for marks tracking in the header.
                </p>
              </div>
            </div>

            <SchemeTable 
              lessons={activeScheme.lessons} 
              metadata={activeScheme.metadata}
              onUpdateLesson={updateLesson} 
              onGenerateResources={handleGenerateResources}
            />
          </div>
        )}
      </main>

      {isLoading && <LoadingOverlay />}
    </div>
  );
};

export default App;

