const { Document, Packer, Paragraph, TextRun, HeadingLevel, AlignmentType, Table, TableRow, TableCell, WidthType, BorderStyle, PageOrientation, VerticalAlign } = docx;

/**
 * Robust sanitization to remove characters that break OpenXML.
 * Specifically removes control characters that are invalid in XML 1.0.
 */
const sanitizeText = (text: any): string => {
  if (text === null || text === undefined) return "";
  const str = String(text);
  // Remove illegal XML characters (control chars except tab, CR, LF)
  // Also removes some common problematic unicode characters
  return str.replace(/[\x00-\x08\x0B\x0C\x0E-\x1F\x7F-\x84\x86-\x9F\uFDD0-\uFDEF\uFFFE\uFFFF]/g, "");
};

const stripHtml = (html: string | undefined | null) => {
  if (!html) return "";
  const tmp = document.createElement("DIV");
  tmp.innerHTML = html;
  const text = tmp.textContent || tmp.innerText || "";
  return sanitizeText(text);
};

/**
 * Creates cell content as a single Paragraph containing multiple TextRuns.
 * Using 'break: 1' within TextRuns is more stable for Word table cells than 
 * multiple Paragraph objects.
 */
const createCellContent = (text: string, size: number, isBold: boolean = false, isWhite: boolean = false) => {
  const sanitized = sanitizeText(text);
  const lines = sanitized.split(/\r?\n/);

  // Word requires at least one TextRun even if string is empty
  if (lines.length === 0 || (lines.length === 1 && lines[0] === "")) {
    return [new Paragraph({
      children: [new TextRun({ text: "", size })]
    })];
  }

  // Use docx.TextRun as the type because the local TextRun constant is a value (constructor) from destructuring.
  const runs: docx.TextRun[] = [];
  lines.forEach((line, index) => {
    runs.push(new TextRun({
      text: line,
      size: size,
      bold: isBold,
      color: isWhite ? "FFFFFF" : undefined,
      break: index > 0 ? 1 : undefined,
    }));
  });

  return [new Paragraph({
    children: runs,
    alignment: AlignmentType.LEFT
  })];
};

// Generate Individual Lesson Plan (Word)
export const generateLessonPlanDoc = async (lesson: Lesson, metadata: SchemeMetadata): Promise<Blob> => {
  const doc = new Document({
    sections: [{
      properties: {},
      children: [
        new Paragraph({ 
          text: `LESSON PLAN: ${sanitizeText(lesson.topic)}`, 
          heading: HeadingLevel.HEADING_1, 
          alignment: AlignmentType.CENTER 
        }),
        new Paragraph({ 
          text: `${sanitizeText(metadata.subject)} | Form ${sanitizeText(metadata.form)} | Term ${sanitizeText(metadata.term)}`, 
          alignment: AlignmentType.CENTER 
        }),
        new Paragraph({ 
          text: `Week ${lesson.week} | Lesson ${lesson.lessonNumber}`, 
          alignment: AlignmentType.CENTER 
        }),
        new Paragraph({ 
          text: `Week Ending: ${sanitizeText(lesson.weekEnding)}`, 
          alignment: AlignmentType.CENTER 
        }),
        new Paragraph({ text: "" }),
        new Paragraph({ text: "Learning Objectives:", heading: HeadingLevel.HEADING_2 }),
        ...createCellContent(lesson.objectives, 24),
        new Paragraph({ text: "Teacher Notes & Content:", heading: HeadingLevel.HEADING_2 }),
        ...(lesson.lessonPlanContent?.split('\n').map(line => new Paragraph({ 
          children: [new TextRun({ text: sanitizeText(line), size: 24 })] 
        })) || []),
        new Paragraph({ text: "Materials Needed:", heading: HeadingLevel.HEADING_2 }),
        ...createCellContent(lesson.resources, 24),
      ],
    }],
  });
  return await Packer.toBlob(doc);
};

// Generate Student Worksheet (PDF)
export const generateWorksheetPdf = (lesson: Lesson, metadata: SchemeMetadata): Blob => {
  const doc = new jsPDF();
  doc.setFontSize(18);
  doc.text(`Worksheet: ${lesson.topic}`, 105, 20, { align: "center" });
  doc.setFontSize(10);
  doc.text(`Name: ________________________  Date: ____________`, 20, 30);
  doc.text(`${metadata.subject} - Form ${metadata.form}`, 160, 30);
  doc.text(`Week Ending: ${lesson.weekEnding}`, 20, 35);

  doc.line(20, 38, 190, 38);

  doc.setFontSize(12);
  const splitContent = doc.splitTextToSize(lesson.worksheetContent || "", 170);
  doc.text(splitContent, 20, 48);

  return doc.output('blob');
};

// Generate Slides (PPTX)
export const generateSlidesPptx = async (lesson: Lesson, metadata: SchemeMetadata): Promise<Blob> => {
  const pptx = new PptxGenJS();

  // Title Slide
  let slide = pptx.addSlide();
  slide.addText(lesson.topic, { x: 1, y: 1.5, w: 8, fontSize: 44, bold: true, align: 'center', color: '363636' });
  slide.addText(`${metadata.subject} | Week ${lesson.week} Lesson ${lesson.lessonNumber}`, { x: 1, y: 2.5, w: 8, fontSize: 24, align: 'center', color: '7F7F7F' });
  slide.addText(`Week Ending: ${lesson.weekEnding}`, { x: 1, y: 3.2, w: 8, fontSize: 18, align: 'center', color: '7F7F7F' });

  // Content Slides
  lesson.slidesContent?.forEach((content, idx) => {
    let s = pptx.addSlide();
    s.addText(`Slide ${idx + 1}: Key Concept`, { x: 0.5, y: 0.5, fontSize: 32, bold: true, color: '003366' });
    s.addText(content, { x: 0.5, y: 1.5, w: 9, h: 5, fontSize: 20, color: '363636', valign: 'top' });
  });

  // @ts-ignore
  const blob = await pptx.write('blob');
  return blob as Blob;
};

// Download Lesson ZIP
export const downloadLessonResourcesZip = async (lesson: Lesson, metadata: SchemeMetadata) => {
  const zip = new JSZip();
  const folderName = `Week${lesson.week}_Lesson${lesson.lessonNumber}_Resources`;
  const folder = zip.folder(folderName);

  const wordBlob = await generateLessonPlanDoc(lesson, metadata);
  const pdfBlob = generateWorksheetPdf(lesson, metadata);
  const pptBlob = await generateSlidesPptx(lesson, metadata);

  folder?.file("lesson_plan.docx", wordBlob);
  folder?.file("worksheet.pdf", pdfBlob);
  folder?.file("slides.pptx", pptBlob);
  folder?.file("video_guide.txt", `VIDEO EXPLATION GUIDE:\n\n${lesson.videoGuideDescription}`);

  const content = await zip.generateAsync({ type: "blob" });
  const link = document.createElement("a");
  link.href = URL.createObjectURL(content);
  link.download = `${folderName}.zip`;
  link.click();
};

// Download Full Package ZIP
export const downloadFullPackageZip = async (scheme: SchemeBook) => {
  const zip = new JSZip();
  const rootName = `${sanitizeText(scheme.metadata.subject)}_Term${sanitizeText(scheme.metadata.term)}_Complete_Package`;
  const root = zip.folder(rootName);

  const schemeDoc = generateSchemePdfDoc(scheme);
  root?.file("scheme-book.pdf", schemeDoc.output('blob'));

  const workbook = generateExcelWorkbook(scheme);
  const excelBuffer = XLSX.write(workbook, { bookType: 'xlsx', type: 'array' });
  root?.file("scheme-book.xlsx", excelBuffer);

  const resFolder = root?.folder("resources");

  for (const lesson of scheme.lessons) {
    const lessonZip = new JSZip();
    const wordBlob = await generateLessonPlanDoc(lesson, scheme.metadata);
    const pdfBlob = generateWorksheetPdf(lesson, scheme.metadata);
    const pptBlob = await generateSlidesPptx(lesson, scheme.metadata);

    lessonZip.file("lesson_plan.docx", wordBlob);
    lessonZip.file("worksheet.pdf", pdfBlob);
    lessonZip.file("slides.pptx", pptBlob);
    lessonZip.file("video_guide.txt", lesson.videoGuideDescription || "");

    const lessonZipBlob = await lessonZip.generateAsync({ type: "blob" });
    resFolder?.file(`Week${lesson.week}_Lesson${lesson.lessonNumber}.zip`, lessonZipBlob);
  }

  const content = await zip.generateAsync({ type: "blob" });
  const link = document.createElement("a");
  link.href = URL.createObjectURL(content);
  link.download = `${rootName}.zip`;
  link.click();
};

const generateSchemePdfDoc = (scheme: SchemeBook) => {
  const doc = new jsPDF({ orientation: "landscape", unit: "mm", format: "a4" });
  doc.setFontSize(18);
  doc.text("SCHEME OF WORK", 148, 15, { align: "center" });
  doc.setFontSize(10);
  doc.text(`Subject: ${scheme.metadata.subject}`, 14, 25);
  doc.text(`Form: ${scheme.metadata.form} | Term: ${scheme.metadata.term}`, 14, 30);
  doc.text(`Teacher: ${scheme.metadata.teacherName}`, 148, 25, { align: "center" });
  doc.text(`Academic Year: ${scheme.metadata.academicYear}`, 148, 30, { align: "center" });

  const body = scheme.lessons.map(l => [
    l.week, l.weekEnding, l.lessonNumber, l.topic, l.objectives, 
    l.concepts, l.activities, l.resources, l.assessment, l.homework, stripHtml(l.evaluation), (l.remarks || '')
  ]);

  autoTable(doc, {
    startY: 40,
    head: [COLUMN_HEADERS.slice(0, -1)],
    body: body,
    theme: 'grid',
    styles: { fontSize: 7, cellPadding: 1 },
    headStyles: { fillColor: [51, 65, 85] }
  });
  return doc;
};

const generateExcelWorkbook = (scheme: SchemeBook) => {
  const data = scheme.lessons.map(l => ({
    "Week": l.week,
    "Week Ending": l.weekEnding,
    "Lesson #": l.lessonNumber,
    "Topic": l.topic,
    "Objectives": l.objectives,
    "Concepts": l.concepts,
    "Activities": l.activities,
    "References": l.resources,
    "Assessment": l.assessment,
    "Homework": l.homework,
    "Evaluation Criteria": stripHtml(l.evaluation),
    "EVALUATION": (l.remarks || '')
  }));
  const worksheet = XLSX.utils.json_to_sheet(data);
  const workbook = XLSX.utils.book_new();
  XLSX.utils.book_append_sheet(workbook, worksheet, "Scheme of Work");
  return workbook;
};

/**
 * Generates an Excel Record Book for 50 students.
 * Includes unique lesson topics as columns.
 */
export const exportRecordBookExcel = (scheme: SchemeBook) => {
  const { metadata, lessons } = scheme;

  const baseHeaders = ["S/N", "Student Name"];
  const topicHeaders = lessons.map(l => `Wk${l.week} L${l.lessonNumber}: ${l.topic}`);
  const finalHeaders = [...baseHeaders, ...topicHeaders, "Total", "Percentage (%)"];

  const maxScoreRow: any = { "S/N": "", "Student Name": "MAX SCORE ALLOWED" };
  topicHeaders.forEach(h => maxScoreRow[h] = "10"); 
  maxScoreRow["Total"] = "";
  maxScoreRow["Percentage (%)"] = "";

  const rows = [maxScoreRow];
  for (let i = 1; i <= 50; i++) {
    const row: any = {
      "S/N": i,
      "Student Name": ""
    };
    topicHeaders.forEach(header => {
      row[header] = ""; 
    });
    row["Total"] = "";
    row["Percentage (%)"] = "";
    rows.push(row);
  }

  const worksheet = XLSX.utils.json_to_sheet(rows, { header: finalHeaders });

  const wscols = [
    { wch: 5 },  
    { wch: 30 }, 
    ...topicHeaders.map(() => ({ wch: 18 })), 
    { wch: 10 },  
    { wch: 15 },  
  ];
  worksheet['!cols'] = wscols;

  const workbook = XLSX.utils.book_new();
  XLSX.utils.book_append_sheet(workbook, worksheet, "Marks Record Book");

  XLSX.writeFile(workbook, `${metadata.subject}_Form${metadata.form}_Marks_Record.xlsx`);
};

/**
 * Exports the entire scheme of work as a Word (.docx) document.
 */
export const exportToWord = async (scheme: SchemeBook) => {
  const { metadata, lessons } = scheme;

  const headers = COLUMN_HEADERS.slice(0, -1);

  const headerRow = new TableRow({
    children: headers.map(header => new TableCell({
      children: createCellContent(header, 18, true, true),
      shading: { fill: "334155" },
      verticalAlign: VerticalAlign.CENTER
    }))
  });

  const lessonRows = lessons.map(l => new TableRow({
    children: [
      (l.week || "").toString(),
      (l.weekEnding || "").toString(),
      (l.lessonNumber || "").toString(),
      (l.topic || "").toString(),
      (l.objectives || "").toString(),
      (l.concepts || "").toString(),
      (l.activities || "").toString(),
      (l.resources || "").toString(),
      (l.assessment || "").toString(),
      (l.homework || "").toString(),
      stripHtml(l.evaluation),
      (l.remarks || "")
    ].map(text => new TableCell({
      children: createCellContent(text, 12), // Reduced size to fit the extra column better
      verticalAlign: VerticalAlign.TOP
    }))
  }));

  const doc = new Document({
    sections: [{
      properties: {
        page: {
          orientation: PageOrientation.LANDSCAPE,
        }
      },
      children: [
        new Paragraph({ 
          text: "SCHEME OF WORK", 
          heading: HeadingLevel.HEADING_1, 
          alignment: AlignmentType.CENTER 
        }),
        new Paragraph({
          children: [
            new TextRun({ 
              text: `Subject: ${sanitizeText(metadata.subject)} | Form: ${sanitizeText(metadata.form)} | Term: ${sanitizeText(metadata.term)}`, 
              bold: true 
            }),
          ],
          alignment: AlignmentType.CENTER
        }),
        new Paragraph({
          children: [
            new TextRun({ 
              text: `Teacher: ${sanitizeText(metadata.teacherName)} | Academic Year: ${sanitizeText(metadata.academicYear)}`, 
              bold: true 
            }),
          ],
          alignment: AlignmentType.CENTER
        }),
        new Paragraph({ text: "" }),
        new Table({
          width: { size: 100, type: WidthType.PERCENTAGE },
          rows: [headerRow, ...lessonRows],
          borders: {
            top: { style: BorderStyle.SINGLE, size: 1 },
            bottom: { style: BorderStyle.SINGLE, size: 1 },
            left: { style: BorderStyle.SINGLE, size: 1 },
            right: { style: BorderStyle.SINGLE, size: 1 },
            insideHorizontal: { style: BorderStyle.SINGLE, size: 1 },
            insideVertical: { style: BorderStyle.SINGLE, size: 1 },
          }
        }),
      ],
    }],
  });

  try {
    const blob = await Packer.toBlob(doc);
    const link = document.createElement("a");
    link.href = URL.createObjectURL(blob);
    // Remove illegal characters from filename
    const safeSubject = sanitizeText(metadata.subject).replace(/[/\\?%*:|"<>]/g, '_');
    link.download = `${safeSubject || 'Scheme'}_Book.docx`;
    link.click();
    setTimeout(() => URL.revokeObjectURL(link.href), 100);
  } catch (error) {
    console.error("Word export failed:", error);
    alert("Word export failed. Please try PDF or Excel instead.");
  }
};

