import { GoogleGenAI, Type } from "@google/genai";
import { SchemeMetadata, Lesson } from "../types";

export interface ExtractedSyllabusInfo {
  subject: string;
  form: string;
  recommendedWeeksPerTerm: number;
}

export const extractSyllabusInfo = async (
  syllabusFile: { data: string, mimeType: string }
): Promise<ExtractedSyllabusInfo> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: {
      parts: [
        { text: "Analyze this syllabus. Identify the subject, target form/grade, and recommended weeks per term (usually 10-13) for a 3-term academic year." },
        { inlineData: syllabusFile }
      ]
    },
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          subject: { type: Type.STRING },
          form: { type: Type.STRING },
          recommendedWeeksPerTerm: { type: Type.INTEGER },
        },
        required: ["subject", "form", "recommendedWeeksPerTerm"],
      }
    }
  });

  try {
    return JSON.parse(response.text.trim());
  } catch (error) {
    return { subject: "", form: "", recommendedWeeksPerTerm: 12 };
  }
};

export const generateSchemeBook = async (
  metadata: SchemeMetadata, 
  syllabusFile?: { data: string, mimeType: string }
): Promise<Partial<Lesson>[]> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const lessonsPerTerm = metadata.weeksPerTerm * metadata.lessonsPerWeek;

  const textPrompt = `
    Act as a Senior Curriculum Specialist. Create a FULL YEAR (3 Terms) Scheme of Work for:
    Subject: ${metadata.subject} | Level: Form ${metadata.form}
    Structure: 3 Terms, ${metadata.weeksPerTerm} weeks per term, ${metadata.lessonsPerWeek} lessons per week.
    Total Lessons: ${lessonsPerTerm * 3}.

    ${syllabusFile ? 'Align strictly with the attached syllabus document. Distribute topics logically across Term 1, Term 2, and Term 3.' : 'Use international standards for this grade level.'}

    Output a sequential list of lessons. Each lesson MUST include the "term" (1, 2, or 3).
    Ensure Term 1 covers foundational topics, Term 2 intermediate, and Term 3 advanced/revision.
  `;

  const contents = syllabusFile 
    ? { parts: [{ text: textPrompt }, { inlineData: syllabusFile }] }
    : textPrompt;

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: contents,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            term: { type: Type.INTEGER },
            week: { type: Type.INTEGER },
            lessonNumber: { type: Type.INTEGER },
            topic: { type: Type.STRING },
            objectives: { type: Type.STRING },
            concepts: { type: Type.STRING },
            activities: { type: Type.STRING },
            resources: { type: Type.STRING },
            assessment: { type: Type.STRING },
            homework: { type: Type.STRING },
            evaluation: { type: Type.STRING },
          },
          required: ["term", "week", "lessonNumber", "topic", "objectives", "concepts", "activities", "resources", "assessment", "homework", "evaluation"],
        }
      }
    }
  });

  try {
    return JSON.parse(response.text.trim());
  } catch (error) {
    throw new Error("Generation failed. Try reducing weeks per term.");
  }
};

export const generateLessonResourcesContent = async (
  lesson: Lesson,
  metadata: SchemeMetadata
): Promise<Pick<Lesson, 'lessonPlanContent' | 'worksheetContent' | 'slidesContent' | 'videoGuideDescription'>> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: `Generate resources for: ${lesson.topic} (${metadata.subject}, Form ${metadata.form}). Objectives: ${lesson.objectives}`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          lessonPlanContent: { type: Type.STRING },
          worksheetContent: { type: Type.STRING },
          slidesContent: { type: Type.ARRAY, items: { type: Type.STRING } },
          videoGuideDescription: { type: Type.STRING },
        },
        required: ["lessonPlanContent", "worksheetContent", "slidesContent", "videoGuideDescription"],
      }
    }
  });
  return JSON.parse(response.text.trim());
};

import React, { useState, useEffect } from 'react';
import { Download, Layout, RotateCcw, Printer, PlusCircle, Sparkles, FolderArchive, Package, Info, GraduationCap, FileText } from 'lucide-react';
import InputForm from './components/InputForm';
import SchemeTable from './components/SchemeTable';
import LoadingOverlay from './components/LoadingOverlay';
import { SchemeBook, SchemeMetadata, Lesson } from './types';
import { generateSchemeBook, generateLessonResourcesContent } from './services/geminiService';
import { getWeekEndingDate } from './utils/dateUtils';
import { exportToPDF, exportToExcel, exportToWord, downloadFullPackageZip, exportRecordBookExcel } from './utils/exportUtils';

const STORAGE_KEY = 'schemegenie_v4_year';

const App: React.FC = () => {
  const [activeScheme, setActiveScheme] = useState<SchemeBook | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [isExportingFull, setIsExportingFull] = useState(false);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        if (Array.isArray(parsed) && parsed.length > 0) setActiveScheme(parsed[0]);
      } catch (e) { }
    }
  }, []);

  useEffect(() => {
    if (activeScheme) localStorage.setItem(STORAGE_KEY, JSON.stringify([activeScheme]));
  }, [activeScheme]);

  const handleGenerate = async (metadata: SchemeMetadata, syllabusFile?: { data: string, mimeType: string }) => {
    setIsLoading(true);
    setError(null);
    try {
      const lessonData = await generateSchemeBook(metadata, syllabusFile);

      const completeLessons: Lesson[] = lessonData.map((l, index) => {
        const term = l.term || 1;
        const week = l.week || 1;
        const startDate = metadata.termStarts[`term${term as 1|2|3}`];

        return {
          id: `lesson-${Date.now()}-${index}`,
          term,
          week,
          lessonNumber: l.lessonNumber || 1,
          topic: l.topic || '',
          objectives: l.objectives || '',
          concepts: l.concepts || '',
          activities: l.activities || '',
          resources: l.resources || '',
          assessment: l.assessment || '',
          homework: l.homework || '',
          evaluation: l.evaluation || '',
          remarks: '',
          weekEnding: getWeekEndingDate(startDate, week),
        };
      });

      setActiveScheme({
        id: `scheme-${Date.now()}`,
        metadata,
        lessons: completeLessons,
        createdAt: Date.now()
      });
    } catch (err: any) {
      setError("AI generation failed. The year-long plan might be too large; try with fewer lessons per week.");
    } finally {
      setIsLoading(false);
    }
  };

  const handleGenerateResources = async (lesson: Lesson) => {
    if (!activeScheme) return;
    updateLesson(lesson.id, 'isGeneratingResources', true);
    try {
      const resources = await generateLessonResourcesContent(lesson, activeScheme.metadata);
      setActiveScheme(prev => prev ? {
        ...prev,
        lessons: prev.lessons.map(l => l.id === lesson.id ? { ...l, ...resources, isGeneratingResources: false } : l)
      } : null);
    } catch (err) {
      alert("Failed to build bundle.");
      updateLesson(lesson.id, 'isGeneratingResources', false);
    }
  };

  const updateLesson = (id: string, field: keyof Lesson, value: any) => {
    setActiveScheme(prev => prev ? {
      ...prev,
      lessons: prev.lessons.map(l => l.id === id ? { ...l, [field]: value } : l)
    } : null);
  };

  return (
    <div className="min-h-screen pb-20">
      <header className="bg-slate-800 text-white shadow-lg no-print">
        <div className="container mx-auto px-6 py-4 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="bg-indigo-600 p-2 rounded-lg"><Package className="w-6 h-6" /></div>
            <div>
              <h1 className="text-xl font-bold">SchemeGenie</h1>
