import { jsPDF } from "jspdf";
import autoTable from "jspdf-autotable";
import * as XLSX from "xlsx";
import * as docx from "docx";
import PptxGenJS from "pptxgenjs";
import JSZip from "jszip";
import { SchemeBook, Lesson, SchemeMetadata } from "../types";
import { COLUMN_HEADERS } from "../constants";

const { Document, Packer, Paragraph, TextRun, HeadingLevel, AlignmentType, Table, TableRow, TableCell, WidthType, BorderStyle, PageOrientation, VerticalAlign } = docx;

const sanitizeText = (text: any): string => {
  if (text === null || text === undefined) return "";
  return String(text).replace(/[\x00-\x08\x0B\x0C\x0E-\x1F\x7F-\x84\x86-\x9F\uFDD0-\uFDEF\uFFFE\uFFFF]/g, "");
};

const createCellContent = (text: string, size: number, isBold: boolean = false) => {
  const sanitized = sanitizeText(text);
  const runs = sanitized.split(/\r?\n/).map((line, idx) => new TextRun({ text: line, size, bold: isBold, break: idx > 0 ? 1 : undefined }));
  return [new Paragraph({ children: runs })];
};

export const exportToPDF = (scheme: SchemeBook) => {
  const doc = new jsPDF({ orientation: "landscape" });
  doc.setFontSize(20);
  doc.text(`${scheme.metadata.subject} - Full Year Scheme`, 148, 15, { align: "center" });

  let startY = 30;
  [1, 2, 3].forEach(termNum => {
    const termLessons = scheme.lessons.filter(l => l.term === termNum);
    if (termLessons.length === 0) return;

    doc.setFontSize(14);
    doc.text(`TERM ${termNum}`, 14, startY);

    const body = termLessons.map(l => [l.week, l.weekEnding, l.topic, l.objectives, l.activities, l.resources]);
    autoTable(doc, {
      startY: startY + 5,
      head: [['Wk', 'Ending', 'Topic', 'Objectives', 'Activities', 'Resources']],
      body: body,
      theme: 'grid',
      styles: { fontSize: 7 }
    });
    // @ts-ignore
    startY = doc.lastAutoTable.finalY + 15;
    if (startY > 180 && termNum < 3) {
      doc.addPage();
      startY = 20;
    }
  });
  doc.save(`${scheme.metadata.subject}_FullYear_Scheme.pdf`);
};

export const exportToExcel = (scheme: SchemeBook) => {
  const data = scheme.lessons.map(l => ({
    "Term": l.term,
    "Week": l.week,
    "Ending": l.weekEnding,
    "Topic": l.topic,
    "Objectives": l.objectives,
    "Activities": l.activities,
    "Resources": l.resources
  }));
  const ws = XLSX.utils.json_to_sheet(data);
  const wb = XLSX.utils.book_new();
  XLSX.utils.book_append_sheet(wb, ws, "Year Plan");
  XLSX.writeFile(wb, `${scheme.metadata.subject}_Scheme.xlsx`);
};

export const exportToWord = async (scheme: SchemeBook) => {
  const children: any[] = [
    new Paragraph({ text: `${scheme.metadata.subject} Yearly Scheme`, heading: HeadingLevel.HEADING_1, alignment: AlignmentType.CENTER })
  ];

  [1, 2, 3].forEach(termNum => {
    const termLessons = scheme.lessons.filter(l => l.term === termNum);
    children.push(new Paragraph({ text: `TERM ${termNum}`, heading: HeadingLevel.HEADING_2, alignment: AlignmentType.LEFT }));

    const rows = termLessons.map(l => new TableRow({
      children: [
        new TableCell({ children: createCellContent(l.week.toString(), 16) }),
        new TableCell({ children: createCellContent(l.topic, 16) }),
        new TableCell({ children: createCellContent(l.objectives, 16) })
      ]
    }));

    children.push(new Table({
      width: { size: 100, type: WidthType.PERCENTAGE },
      rows: [
        new TableRow({ children: ['Wk', 'Topic', 'Objectives'].map(h => new TableCell({ children: createCellContent(h, 18, true) })) }),
        ...rows
      ]
    }));
    children.push(new Paragraph({ text: "" }));
  });

  const doc = new Document({ sections: [{ properties: { page: { orientation: PageOrientation.LANDSCAPE } }, children }] });
  const blob = await Packer.toBlob(doc);
  const link = document.createElement("a");
  link.href = URL.createObjectURL(blob);
  link.download = "FullYear_Scheme.docx";
  link.click();
};

