export const generateSchemeBook = async (
  metadata: SchemeMetadata, 
  syllabusFile?: { data: string, mimeType: string }
): Promise<Partial<Lesson>[]> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const totalLessonsRequested = metadata.weeksPerTerm * metadata.lessonsPerWeek * 3;

  const textPrompt = `
    Act as a Senior Curriculum Specialist. Create a professional FULL YEAR (3 Terms) Scheme of Work.

    CONTEXT:
    - Subject: ${metadata.subject}
    - Level: Form ${metadata.form}
    - Structure: 3 Terms, ${metadata.weeksPerTerm} weeks per term, ${metadata.lessonsPerWeek} lessons per week.
    - Total Lesson Count: ${totalLessonsRequested} lessons.

    SYLLABUS CONTENT ALLOCATION:
    If a syllabus file is provided, you MUST:
    1. READ the entire syllabus provided.
    2. DIVIDE the total syllabus content into THREE EQUAL parts.
    3. ASSIGN Term 1 content to the first 1/3rd of the year (${metadata.weeksPerTerm * metadata.lessonsPerWeek} lessons).
    4. ASSIGN Term 2 content to the middle 1/3rd of the year.
    5. ASSIGN Term 3 content to the final 1/3rd of the year.
    6. Ensure NO content from the syllabus is skipped.
    7. Ensure logical progression where Term 1 builds foundations and Term 3 covers the most advanced topics from the syllabus.

    TERMINOLOGY & STYLE:
    - Use the word "Pupils" instead of "Students".
    - Objectives MUST start with "Pupils will be able to..."
    - The scheme should be comprehensive and professionally detailed.

    OUTPUT FORMAT:
    Provide an array of exactly ${totalLessonsRequested} lesson objects with these fields:
    - term: (1, 2, or 3)
    - week: (1 to ${metadata.weeksPerTerm} within that term)
    - lessonNumber: (sequential starting from 1 in each term)
    - topic: (derived directly from syllabus section)
    - objectives: (Starting with: Pupils will be able to...)
    - activities: (classroom tasks)
    - resources: (materials)
    - assessment: (check for understanding)
    - homework: (practice)
    - evaluation: (success criteria)
  `;

  const contents = syllabusFile 
    ? { parts: [{ text: textPrompt }, { inlineData: syllabusFile }] }
    : textPrompt;

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: contents,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            term: { type: Type.INTEGER },
            week: { type: Type.INTEGER },
            lessonNumber: { type: Type.INTEGER },
            topic: { type: Type.STRING },
            objectives: { type: Type.STRING },
            concepts: { type: Type.STRING },
            activities: { type: Type.STRING },
            resources: { type: Type.STRING },
            assessment: { type: Type.STRING },
            homework: { type: Type.STRING },
            evaluation: { type: Type.STRING },
          },
          required: ["term", "week", "lessonNumber", "topic", "objectives", "activities", "resources", "assessment", "homework", "evaluation"],
        }
      }
    }
  });

  try {
    return JSON.parse(response.text.trim());
  } catch (error) {
    throw new Error("Generation failed. The curriculum requested is too large or the AI encountered an error. Try reducing the number of lessons per week.");
  }
};

