import React, { useState, useEffect } from 'react';
import { Download, Layout, RotateCcw, Printer, PlusCircle, Sparkles, FolderArchive, Package, Info, GraduationCap, FileText } from 'lucide-react';
import InputForm from './components/InputForm';
import SchemeTable from './components/SchemeTable';
import LoadingOverlay from './components/LoadingOverlay';
import { SchemeBook, SchemeMetadata, Lesson } from './types';
import { generateSchemeBook, generateLessonResourcesContent } from './services/geminiService';
import { getWeekEndingDate } from './utils/dateUtils';
import { exportToPDF, exportToExcel, exportToWord, downloadFullPackageZip, exportRecordBookExcel } from './utils/exportUtils';

const STORAGE_KEY = 'schemegenie_v7_balanced';

const App: React.FC = () => {
  const [activeScheme, setActiveScheme] = useState<SchemeBook | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [isExportingFull, setIsExportingFull] = useState(false);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        if (Array.isArray(parsed) && parsed.length > 0) setActiveScheme(parsed[0]);
      } catch (e) { }
    }
  }, []);

  useEffect(() => {
    if (activeScheme) localStorage.setItem(STORAGE_KEY, JSON.stringify([activeScheme]));
  }, [activeScheme]);

  const handleGenerate = async (metadata: SchemeMetadata, syllabusFile?: { data: string, mimeType: string }) => {
    setIsLoading(true);
    setError(null);
    try {
      const lessonData = await generateSchemeBook(metadata, syllabusFile);

      const totalLessons = lessonData.length;
      // Calculate how many lessons per term to ensure "almost equal" distribution
      // Term 1 gets floor(total/3), Term 2 gets floor(total/3), Term 3 gets the remainder
      const baseLessonsPerTerm = Math.floor(totalLessons / 3);

      const completeLessons: Lesson[] = lessonData.map((l, index) => {
        // Enforce balanced division across 3 terms
        let term = 1;
        let indexInTerm = index;

        if (index < baseLessonsPerTerm) {
          term = 1;
          indexInTerm = index;
        } else if (index < baseLessonsPerTerm * 2) {
          term = 2;
          indexInTerm = index - baseLessonsPerTerm;
        } else {
          term = 3;
          indexInTerm = index - (baseLessonsPerTerm * 2);
        }

        // Calculate week within term based on metadata lessons per week
        const weekInTerm = Math.floor(indexInTerm / metadata.lessonsPerWeek) + 1;

        // Sequential week numbering across the entire year
        // Term 1: 1...W, Term 2: W+1...2W, Term 3: 2W+1...3W
        const sequentialWeek = (term - 1) * metadata.weeksPerTerm + weekInTerm;
        const globalLessonNumber = index + 1;

        const startDate = metadata.termStarts[`term${term as 1|2|3}`];

        return {
          id: `lesson-${Date.now()}-${index}`,
          term,
          week: sequentialWeek,
          lessonNumber: globalLessonNumber,
          topic: l.topic || '',
          objectives: l.objectives || '',
          concepts: l.concepts || '',
          activities: l.activities || '',
          resources: l.resources || '',
          assessment: l.assessment || '',
          homework: l.homework || '',
          evaluation: l.evaluation || '',
          remarks: '',
          weekEnding: getWeekEndingDate(startDate, weekInTerm),
        };
      });

      setActiveScheme({
        id: `scheme-${Date.now()}`,
        metadata,
        lessons: completeLessons,
        createdAt: Date.now()
      });
    } catch (err: any) {
      setError("AI generation failed. Ensure your syllabus is readable and try again.");
    } finally {
      setIsLoading(false);
    }
  };

  const handleGenerateResources = async (lesson: Lesson) => {
    if (!activeScheme) return;
    updateLesson(lesson.id, 'isGeneratingResources', true);
    try {
      const resources = await generateLessonResourcesContent(lesson, activeScheme.metadata);
      setActiveScheme(prev => prev ? {
        ...prev,
        lessons: prev.lessons.map(l => l.id === lesson.id ? { ...l, ...resources, isGeneratingResources: false } : l)
      } : null);
    } catch (err) {
      alert("Failed to build bundle.");
      updateLesson(lesson.id, 'isGeneratingResources', false);
    }
  };

  const updateLesson = (id: string, field: keyof Lesson, value: any) => {
    setActiveScheme(prev => prev ? {
      ...prev,
      lessons: prev.lessons.map(l => l.id === id ? { ...l, [field]: value } : l)
    } : null);
  };

  return (
    <div className="min-h-screen pb-20">
      <header className="bg-slate-800 text-white shadow-lg no-print">
        <div className="container mx-auto px-6 py-4 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="bg-indigo-600 p-2 rounded-lg"><Package className="w-6 h-6" /></div>
            <div>
              <h1 className="text-xl font-bold">SchemeGenie</h1>
              <p className="text-xs text-indigo-300 italic">Sequential Full Year Curriculum</p>
            </div>
          </div>
          <div className="flex items-center gap-4">
            {activeScheme && (
              <div className="hidden md:flex items-center gap-2">
                <button onClick={() => exportRecordBookExcel(activeScheme)} className="bg-emerald-600 hover:bg-emerald-500 text-white px-4 py-2 rounded-lg text-sm font-bold shadow-md"><GraduationCap className="w-4 h-4 mr-2 inline" />Record Book</button>
                <button onClick={() => downloadFullPackageZip(activeScheme)} disabled={isExportingFull} className="bg-indigo-600 hover:bg-indigo-500 text-white px-4 py-2 rounded-lg text-sm font-bold shadow-md"><FolderArchive className="w-4 h-4 mr-2 inline" />Full Package</button>
                <button onClick={() => exportToPDF(activeScheme)} className="bg-slate-700 hover:bg-slate-600 text-white px-4 py-2 rounded-lg text-sm font-medium"><Download className="w-4 h-4 inline mr-1" />PDF</button>
                <button onClick={() => exportToWord(activeScheme)} className="bg-slate-700 hover:bg-slate-600 text-white px-4 py-2 rounded-lg text-sm font-medium"><FileText className="w-4 h-4 inline mr-1" />Word</button>
              </div>
            )}
            <button onClick={() => { if(confirm("Reset year plan?")) setActiveScheme(null); }} className="p-2 hover:bg-slate-700 rounded-lg text-slate-400 hover:text-white"><RotateCcw className="w-5 h-5" /></button>
          </div>
        </div>
      </header>
      <main className="container mx-auto px-6 py-8">
        {!activeScheme ? (
          <div className="max-w-4xl mx-auto space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-700">
            <div className="text-center space-y-4 py-10">
              <h2 className="text-5xl font-extrabold text-slate-800">Balanced Syllabus Planner</h2>
              <p className="text-lg text-slate-500">Automatically map your syllabus across three terms with equal content weight.</p>
            </div>
            <InputForm onGenerate={handleGenerate} />
            {error && <div className="bg-red-50 border border-red-200 text-red-700 px-6 py-4 rounded-xl flex items-center gap-3"><Layout className="w-5 h-5" />{error}</div>}
          </div>
        ) : (
          <div className="space-y-6">
            <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6 flex items-center justify-between no-print">
              <p className="text-lg font-bold text-slate-800">{activeScheme.metadata.subject} | {activeScheme.metadata.academicYear}</p>
              <div className="flex gap-3">
                <button onClick={() => setActiveScheme(null)} className="border px-4 py-2 rounded-lg text-sm font-semibold hover:bg-slate-50">New Year Plan</button>
                <button onClick={() => window.print()} className="bg-slate-100 px-4 py-2 rounded-lg text-sm font-semibold hover:bg-slate-200">Print All Terms</button>
              </div>
            </div>
            <SchemeTable lessons={activeScheme.lessons} metadata={activeScheme.metadata} onUpdateLesson={updateLesson} onGenerateResources={handleGenerateResources} />
          </div>
        )}
      </main>
      {isLoading && <LoadingOverlay />}
    </div>
  );
};

export default App;

