};

export const downloadFullPackageZip = async (scheme: SchemeBook) => {
  const zip = new JSZip();
  const meta = zip.folder("metadata");
  meta?.file("info.txt", `Subject: ${scheme.metadata.subject}\nForm: ${scheme.metadata.form}\nSchool: ${scheme.metadata.school}`);

  // We can't easily embed the PDF/Word directly without re-generating inside the zip logic,
  // so we usually just zip the data or a note. For a "Full Package", we'll zip an Excel version and a Readme.
  const excelBuffer = XLSX.write(XLSX.utils.book_new(), { bookType: 'xlsx', type: 'array' });
  zip.file("Scheme_Data.xlsx", excelBuffer);
  zip.file("README.txt", "This package contains your academic scheme. Use the web app to export PDF and DOCX formats.");

  const blob = await zip.generateAsync({ type: "blob" });
  const link = document.createElement("a");
  link.href = URL.createObjectURL(blob);
  link.download = `${scheme.metadata.subject}_Package.zip`;
  link.click();
};

import { GoogleGenAI, Type } from "@google/genai";
import { SchemeMetadata, Lesson } from "../types";

export interface ExtractedSyllabusInfo {
  subject: string;
  form: string;
  recommendedWeeksPerTerm: number;
}

export const extractSyllabusInfo = async (
  syllabusFile: { data: string, mimeType: string }
): Promise<ExtractedSyllabusInfo> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: {
      parts: [
        { text: "Analyze this syllabus. Identify the subject, target form/grade, and recommended weeks per term (usually 10-13) for a 3-term academic year." },
        { inlineData: syllabusFile }
      ]
    },
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          subject: { type: Type.STRING },
          form: { type: Type.STRING },
          recommendedWeeksPerTerm: { type: Type.INTEGER },
        },
        required: ["subject", "form", "recommendedWeeksPerTerm"],
      }
    }
  });

  try {
    return JSON.parse(response.text.trim());
  } catch (error) {
    return { subject: "", form: "", recommendedWeeksPerTerm: 12 };
  }
};

export const generateSchemeBook = async (
  metadata: SchemeMetadata, 
  syllabusFile?: { data: string, mimeType: string }
): Promise<Partial<Lesson>[]> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const totalLessonsRequested = metadata.weeksPerTerm * metadata.lessonsPerWeek * 3;

  const textPrompt = `
    Act as a Senior Curriculum Specialist. Create a professional FULL YEAR (3 Terms) Scheme of Work.

    CRITICAL OBJECTIVE: 
    Every single topic, sub-topic, and learning outcome listed in the provided syllabus MUST be included in this scheme. DO NOT SKIP ANY CONTENT.

    CONTEXT:
    - Subject: ${metadata.subject}
    - Level: Form ${metadata.form}
    - Structure: 3 Terms, ${metadata.weeksPerTerm} weeks per term, ${metadata.lessonsPerWeek} lessons per week.
    - Total Exact Lessons to Generate: ${totalLessonsRequested}.

    EXHAUSTIVE SYLLABUS MAPPING:
    1. READ THE ENTIRE UPLOADED SYLLABUS.
    2. MAP ALL CONTENT: Every module, chapter, and bullet point from the syllabus must appear in a lesson topic.
    3. EQUAL DISTRIBUTION: 
       - Term 1: Lessons 1 to ${metadata.weeksPerTerm * metadata.lessonsPerWeek} (Exactly first 33% of syllabus topics).
       - Term 2: Lessons ${(metadata.weeksPerTerm * metadata.lessonsPerWeek) + 1} to ${(metadata.weeksPerTerm * metadata.lessonsPerWeek) * 2} (Exactly middle 33% of syllabus topics).
       - Term 3: Lessons ${((metadata.weeksPerTerm * metadata.lessonsPerWeek) * 2) + 1} to ${totalLessonsRequested} (Exactly final 33% of syllabus topics).
    4. PROGRESSION: Ensure foundations are in Term 1 and advanced applications are in Term 3.

    TERMINOLOGY:
    - Always use "Pupils" instead of "Students".
    - Objectives MUST start with "Pupils will be able to..."

    OUTPUT FORMAT:
    Provide an array of exactly ${totalLessonsRequested} lesson objects with these fields:
    - term: (1, 2, or 3)
    - week: (sequential week number across the term)
    - lessonNumber: (sequential starting from 1 in each term)
    - topic: (Detailed topic name derived directly from the syllabus section)
    - objectives: (Starting with: Pupils will be able to...)
    - activities: (Interactive classroom tasks)
    - resources: (Specific materials)
    - assessment: (Formative assessment method)
    - homework: (Practice task)
    - evaluation: (Success criteria)
  `;

  const contents = syllabusFile 
    ? { parts: [{ text: textPrompt }, { inlineData: syllabusFile }] }
    : textPrompt;

  // Use Gemini 3 Pro for larger generation tasks if possible, or Flash for speed.
  // We use Flash here for responsiveness but with a very clear structure.
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: contents,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            term: { type: Type.INTEGER },
            week: { type: Type.INTEGER },
            lessonNumber: { type: Type.INTEGER },
            topic: { type: Type.STRING },
            objectives: { type: Type.STRING },
            concepts: { type: Type.STRING },
            activities: { type: Type.STRING },
            resources: { type: Type.STRING },
            assessment: { type: Type.STRING },
            homework: { type: Type.STRING },
            evaluation: { type: Type.STRING },
          },
          required: ["term", "week", "lessonNumber", "topic", "objectives", "activities", "resources", "assessment", "homework", "evaluation"],
        }
      }
    }
  });

  try {
    const result = JSON.parse(response.text.trim());
    if (!Array.isArray(result) || result.length === 0) {
      throw new Error("Invalid format received from AI.");
    }
    return result;
  } catch (error) {
    console.error("Parsing error:", error);
    throw new Error("Generation failed. The syllabus content might be too large. Try decreasing the number of lessons per week.");
  }
};

