): Promise<Pick<Lesson, 'lessonPlanContent' | 'worksheetContent' | 'slidesContent' | 'videoGuideDescription'>> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: `Generate a comprehensive teaching bundle for the following lesson:

    LESSON DETAILS:
    - Subject: ${metadata.subject}
    - Level: Form ${metadata.form}
    - Topic: ${lesson.topic}
    - Objectives: ${lesson.objectives}
    - Planned Activities: ${lesson.activities}

    Please structure the response with the following comprehensive details:

    1. [lessonPlanContent]: A highly detailed professional lesson plan.
       - Include: Starter Activity (5 mins), Introduction (10 mins), Main Teaching Phase (20 mins), Plenary/Summary (5 mins).
       - Ensure "Pupils" terminology is used.
       - Include specific differentiation strategies.

    2. [worksheetContent]: A ready-to-print pupil worksheet.
       - Section 1: Recall (5 quick questions).
       - Section 2: Application (Structured problems or tasks).
       - Section 3: Extension (A challenging task for faster pupils).

    3. [slidesContent]: Content for 5 presentation slides.
       - Each item in the array is a slide. 
       - Format: "SLIDE [X] TITLE: [Title] | CONTENT: [Bullet points] | TEACHER NOTES: [Notes]".

    4. [videoGuideDescription]: A short script/description for a teacher to record a video guide for this lesson.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          lessonPlanContent: { 
            type: Type.STRING,
            description: "Detailed step-by-step lesson plan with timings."
          },
          worksheetContent: { 
            type: Type.STRING,
            description: "Full printable worksheet content with clear sections."
          },
          slidesContent: { 
            type: Type.ARRAY, 
            items: { type: Type.STRING },
            description: "Array of 5 slide contents including titles and notes."
          },
          videoGuideDescription: { 
            type: Type.STRING,
            description: "Short guide/script for an instructional video."
          },
        },
        required: ["lessonPlanContent", "worksheetContent", "slidesContent", "videoGuideDescription"],
      }
    }
  });
  return JSON.parse(response.text.trim());
};

import React, { useState, useEffect } from 'react';
import { Download, Layout, RotateCcw, Printer, PlusCircle, Sparkles, FolderArchive, Package, Info, GraduationCap, FileText, FileDown, FileCheck } from 'lucide-react';
