import { SchemeBook, SchemeMetadata, Lesson } from './types';
import { generateSchemeBook, generateLessonResourcesContent } from './services/geminiService';
import { getWeekEndingDate } from './utils/dateUtils';
import { exportToPDF, exportToExcel, exportToWord, downloadFullPackageZip, exportRecordBookExcel } from './utils/exportUtils';

const STORAGE_KEY = 'schemegenie_v9_72lessons';

const App: React.FC = () => {
  const [activeScheme, setActiveScheme] = useState<SchemeBook | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [isExportingFull, setIsExportingFull] = useState(false);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        if (Array.isArray(parsed) && parsed.length > 0) setActiveScheme(parsed[0]);
      } catch (e) { }
    }
  }, []);

  useEffect(() => {
    if (activeScheme) localStorage.setItem(STORAGE_KEY, JSON.stringify([activeScheme]));
  }, [activeScheme]);

  const handleGenerate = async (metadata: SchemeMetadata, syllabusFile?: { data: string, mimeType: string }) => {
    setIsLoading(true);
    setError(null);
    try {
      const lessonData = await generateSchemeBook(metadata, syllabusFile);

      const totalLessonsCount = lessonData.length;
      // We expect 216 lessons from the AI. We distribute them in blocks of 72.
      const lessonsPerTerm = 72;

      const completeLessons: Lesson[] = lessonData.map((l, index) => {
        // Enforce 72 lessons per term distribution
        const term = Math.min(3, Math.floor(index / lessonsPerTerm) + 1);
        const indexInTerm = index % lessonsPerTerm;

        // Reset week numbering per term starting at 1
        const weekInTerm = Math.floor(indexInTerm / metadata.lessonsPerWeek) + 1;
        // Reset lesson numbering per term starting at 1
        const lessonNumberInTerm = indexInTerm + 1;

        const startDate = metadata.termStarts[`term${term as 1|2|3}`];

        return {
          id: `lesson-${Date.now()}-${index}`,
          term,
          week: weekInTerm,
          lessonNumber: lessonNumberInTerm,
          topic: l.topic || '',
          objectives: l.objectives || '',
          concepts: l.concepts || '',
          activities: l.activities || '',
          resources: l.resources || '',
          assessment: l.assessment || '',
          homework: l.homework || '',
          evaluation: l.evaluation || '',
          remarks: '',
          weekEnding: getWeekEndingDate(startDate, weekInTerm),
        };
      });

      setActiveScheme({
        id: `scheme-${Date.now()}`,
        metadata,
        lessons: completeLessons,
        createdAt: Date.now()
      });
    } catch (err: any) {
      setError(err.message || "AI generation failed. Ensure your syllabus is readable and try again.");
    } finally {
      setIsLoading(false);
    }
  };

  const handleGenerateResources = async (lesson: Lesson) => {
    if (!activeScheme) return;
    updateLesson(lesson.id, 'isGeneratingResources', true);
    try {
      const resources = await generateLessonResourcesContent(lesson, activeScheme.metadata);
      setActiveScheme(prev => prev ? {
        ...prev,
        lessons: prev.lessons.map(l => l.id === lesson.id ? { ...l, ...resources, isGeneratingResources: false } : l)
      } : null);
    } catch (err) {
      alert("Failed to build bundle.");
      updateLesson(lesson.id, 'isGeneratingResources', false);
    }
  };

  const updateLesson = (id: string, field: keyof Lesson, value: any) => {
    setActiveScheme(prev => prev ? {
      ...prev,
      lessons: prev.lessons.map(l => l.id === id ? { ...l, [field]: value } : l)
    } : null);
  };

  return (
    <div className="min-h-screen pb-20 bg-slate-50">
      <header className="bg-slate-800 text-white shadow-lg no-print sticky top-0 z-40">
        <div className="container mx-auto px-4 md:px-6 py-3 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="bg-indigo-600 p-1.5 rounded-lg shrink-0"><Package className="w-5 h-5 md:w-6 md:h-6" /></div>
            <div>
              <h1 className="text-lg md:text-xl font-bold leading-tight">SchemeGenie</h1>
              <p className="text-[10px] md:text-xs text-indigo-300 italic">72 Lessons per Term • Full Year Plan</p>
            </div>
          </div>
          <div className="flex items-center gap-2">
            {activeScheme && (
              <button onClick={() => { if(confirm("Discard current plan?")) setActiveScheme(null); }} className="p-2 hover:bg-slate-700 rounded-lg text-slate-400 hover:text-white" title="New Scheme">
                <RotateCcw className="w-5 h-5" />
              </button>
            )}
            <div className="h-6 w-px bg-slate-700 mx-1 hidden md:block"></div>
            {activeScheme && (
              <div className="flex items-center gap-1 md:gap-2">
                 <button onClick={() => exportToPDF(activeScheme)} className="bg-rose-600 hover:bg-rose-500 text-white p-2 md:px-3 md:py-1.5 rounded-lg text-xs font-bold transition-all shadow-sm flex items-center gap-1.5">
                   <FileDown className="w-4 h-4" />
                   <span className="hidden sm:inline">PDF</span>
                 </button>
                 <button onClick={() => exportToWord(activeScheme)} className="bg-blue-600 hover:bg-blue-500 text-white p-2 md:px-3 md:py-1.5 rounded-lg text-xs font-bold transition-all shadow-sm flex items-center gap-1.5">
                   <FileText className="w-4 h-4" />
                   <span className="hidden sm:inline">DOCX</span>
                 </button>
              </div>
            )}
          </div>
        </div>
      </header>

      <main className="container mx-auto px-4 md:px-6 py-8">
        {!activeScheme ? (
          <div className="max-w-4xl mx-auto space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-700">
            <div className="text-center space-y-4 py-10">
              <h2 className="text-4xl md:text-6xl font-extrabold text-slate-800 tracking-tight">Full Year Syllabus Mapper</h2>
              <p className="text-base md:text-xl text-slate-500 max-w-2xl mx-auto">
                Generate 216 comprehensive lessons (72 per term) mapped directly from your syllabus.
              </p>
            </div>
            <InputForm onGenerate={handleGenerate} />
            {error && <div className="bg-red-50 border border-red-200 text-red-700 px-6 py-4 rounded-xl flex items-center gap-3 mt-4"><Layout className="w-5 h-5" />{error}</div>}
          </div>
        ) : (
          <div className="space-y-8">
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 no-print">
              <div className="lg:col-span-2 bg-white rounded-xl shadow-sm border border-slate-200 p-6 flex flex-col justify-center">
                <div className="flex items-start justify-between">
                  <div>
                    <h2 className="text-2xl font-black text-slate-800 uppercase tracking-tight">{activeScheme.metadata.subject}</h2>
                    <p className="text-slate-500 font-medium">{activeScheme.metadata.school} • {activeScheme.metadata.form} • {activeScheme.metadata.academicYear}</p>
                    <div className="mt-4 flex flex-wrap gap-2">
                       <span className="bg-indigo-50 text-indigo-700 px-3 py-1 rounded-full text-xs font-bold flex items-center gap-1">
                         <FileCheck className="w-3 h-3" /> 216 Total Lessons
                       </span>
                       <span className="bg-emerald-50 text-emerald-700 px-3 py-1 rounded-full text-xs font-bold">
                         72 Lessons per Term
                       </span>
                    </div>
                  </div>
                  <button onClick={() => setActiveScheme(null)} className="text-slate-400 hover:text-rose-500 transition-colors">
                    <X className="w-6 h-6" />
                  </button>
                </div>
              </div>

              <div className="bg-slate-800 rounded-xl shadow-lg p-6 text-white space-y-4">
                <h3 className="text-sm font-bold uppercase tracking-widest text-slate-400">Export Document</h3>
                <div className="grid grid-cols-2 gap-3">
                  <button onClick={() => exportToPDF(activeScheme)} className="flex flex-col items-center justify-center gap-2 bg-slate-700 hover:bg-rose-600 p-4 rounded-xl transition-all border border-slate-600 group">
                    <FileDown className="w-8 h-8 group-hover:scale-110 transition-transform" />
                    <span className="text-[10px] font-black uppercase">Download PDF</span>
                  </button>
                  <button onClick={() => exportToWord(activeScheme)} className="flex flex-col items-center justify-center gap-2 bg-slate-700 hover:bg-blue-600 p-4 rounded-xl transition-all border border-slate-600 group">
                    <FileText className="w-8 h-8 group-hover:scale-110 transition-transform" />
                    <span className="text-[10px] font-black uppercase">Download DOCX</span>
                  </button>
                  <button onClick={() => exportRecordBookExcel(activeScheme)} className="flex flex-col items-center justify-center gap-2 bg-slate-700 hover:bg-emerald-600 p-4 rounded-xl transition-all border border-slate-600 group">
                    <GraduationCap className="w-8 h-8 group-hover:scale-110 transition-transform" />
                    <span className="text-[10px] font-black uppercase">Record Book</span>
                  </button>
                  <button onClick={() => downloadFullPackageZip(activeScheme)} className="flex flex-col items-center justify-center gap-2 bg-slate-700 hover:bg-indigo-600 p-4 rounded-xl transition-all border border-slate-600 group">
                    <FolderArchive className="w-8 h-8 group-hover:scale-110 transition-transform" />
                    <span className="text-[10px] font-black uppercase">Full Package</span>
                  </button>
                </div>
              </div>
            </div>

            <SchemeTable lessons={activeScheme.lessons} metadata={activeScheme.metadata} onUpdateLesson={updateLesson} onGenerateResources={handleGenerateResources} />
          </div>
        )}
      </main>
      {isLoading && <LoadingOverlay />}
    </div>
  );
};

