/**
 * Generates lessons for a specific term to ensure the model doesn't hit output limits.
 */
export const generateTermLessons = async (
  term: number,
  metadata: SchemeMetadata, 
  syllabusFile?: { data: string, mimeType: string }
): Promise<Partial<Lesson>[]> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const termContext = [
    "Introductory topics and foundation units.",
    "Mid-year core concepts and complex applications.",
    "Advanced units, final chapters, and comprehensive revision."
  ][term - 1];

  const textPrompt = `
    Act as a Senior Curriculum Specialist. You are creating the detailed Scheme of Work for TERM ${term} ONLY.

    CRITICAL MANDATE: 
    - You MUST generate EXACTLY 72 individual lessons for this term.
    - Each lesson must be a unique object in the array.
    - The content must cover: ${termContext} based on the syllabus provided.

    CONTENT REQUIREMENTS:
    - Use "Pupils" terminology.
    - Resources must be detailed (textbooks, page numbers, specific lab tools, or video links).
    - Evaluation MUST contain specific success criteria (e.g. "Pupils can correctly identify 5 parts of the heart").

    Metadata:
    - Subject: ${metadata.subject}
    - Level: Form ${metadata.form}
    - Term Number: ${term}

    Output format:
    Return an array of EXACTLY 72 objects.
    Each object: { "term": ${term}, "week": number, "lessonNumber": number, "topic": string, "objectives": string, "activities": string, "resources": string, "assessment": string, "homework": string, "evaluation": string }
  `;

  const contents = syllabusFile 
    ? { parts: [{ text: textPrompt }, { inlineData: syllabusFile }] }
    : textPrompt;

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: contents,
    config: {
      thinkingConfig: { thinkingBudget: 1000 },
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            term: { type: Type.INTEGER },
            week: { type: Type.INTEGER },
            lessonNumber: { type: Type.INTEGER },
            topic: { type: Type.STRING },
            objectives: { type: Type.STRING },
            activities: { type: Type.STRING },
            resources: { type: Type.STRING },
            assessment: { type: Type.STRING },
            homework: { type: Type.STRING },
            evaluation: { type: Type.STRING },
          },
          required: ["term", "week", "lessonNumber", "topic", "objectives", "activities", "resources", "assessment", "homework", "evaluation"],
        }
      }
    }
  });

  try {
    const result = JSON.parse(response.text.trim());
    if (!Array.isArray(result)) throw new Error("Output is not an array");
    return result;
  } catch (error) {
    console.error(`Term ${term} Generation failed:`, error);
    throw new Error(`Failed to generate Term ${term}. Please try again.`);
  }
};

